function AmbientMesh({ intensity = 1 }) {
  const blobs = [
    { c: C.mint, x: "8%", y: "12%", s: 420, d: 0 }, { c: C.pistachio, x: "78%", y: "8%", s: 360, d: 2 },
    { c: C.jadeLight, x: "65%", y: "70%", s: 480, d: 4 }, { c: C.mintLight, x: "15%", y: "75%", s: 340, d: 1.4 },
    { c: C.teal, x: "45%", y: "40%", s: 380, d: 3 },
  ];
  return (
    <div className="absolute inset-0 overflow-hidden pointer-events-none">
      {blobs.map((b, i) => (
        <motion.div key={i} className="absolute rounded-full" style={{ left: b.x, top: b.y, width: b.s, height: b.s, background: b.c, opacity: 0.32 * intensity, filter: "blur(85px)" }}
          animate={{ x: [0, 40, -30, 0], y: [0, -30, 20, 0], scale: [1, 1.12, 0.95, 1] }} transition={{ duration: 14 + i * 2, repeat: Infinity, ease: "easeInOut", delay: b.d }} />
      ))}
    </div>
  );
}

