/* ===================================================================== */
export default function RotonAdminPortal() {
  const [user, setUser] = useState(null);
  const [settings, setSettings] = useState({ supabaseUrl: "", supabaseKey: "", supabaseBucket: "", currency: "INR", connected: false });
  const [settingsLoaded, setSettingsLoaded] = useState(false);
  useEffect(() => { (async () => { setSettings(await loadKey("roton:settings", settings)); setSettingsLoaded(true); })(); }, []);
  useEffect(() => { if (settingsLoaded) saveKey("roton:settings", settings); }, [settings, settingsLoaded]);

  return user ? (
    <Dashboard user={user} onLogout={() => setUser(null)} settings={settings} setSettings={setSettings} />
  ) : (
    <LoginGateway onAuth={setUser} settings={settings} />
  );
}
